+            tower.angle = Math.atan2(target.y - tower.y, target.x - tower.x);
+            tower.cooldown = 1 / tower.fireRate;
+
+            if (tower.type === 'lightning') {
+                sfx.lightning();
+                // Instant chain damage
+                const hit = new Set([target]);
+                target.hp -= tower.damage;
+                addParticles(target.x, target.y + BAR_H, target.color);
+                let last = target;
+                for (let c = 1; c < tower.chainCount; c++) {
+                    let next = null, bestD = Infinity;
+                    for (const e of enemies) {
+                        if (e.dead || hit.has(e)) continue;
+                        const d = Math.hypot(e.x - last.x, e.y - last.y);
+                        if (d < tower.chainRange && d < bestD) { bestD = d; next = e; }
+                    }
+                    if (!next) break;
+                    hit.add(next);
+                    next.hp -= tower.damage * 0.7;
+                    addParticles(next.x, next.y + BAR_H, next.color);
+                    // Lightning bolt visual via projectile stub
+                    projectiles.push({
+                        x: last.x, y: last.y,
+                        tx: next.x, ty: next.y,
+                        target: null, done: true,
+                        visual: true, visualLife: 0.12,
+                        color: tower.projColor, type: 'lightning',
+                    });
+                    last = next;
+                }
+                // Connector from tower to first target
+                projectiles.push({
+                    x: tower.x, y: tower.y,
+                    tx: target.x, ty: target.y,
+                    target: null, done: true,
+                    visual: true, visualLife: 0.12,
+                    color: tower.projColor, type: 'lightning',
+                });
+                // Kill check
+                for (const e of hit) {
+                    if (e.hp <= 0) killEnemy(e);
+                }
+            } else {
+                const proj = createProjectile(tower, target);
+                projectiles.push(proj);
+                if (tower.type === 'cannon') sfx.cannon();
+                else if (tower.type === 'single') sfx.shoot();
+                else if (tower.type === 'slow') sfx.ice();
+                else sfx.shoot();
+            }
+        }
+
+        function killEnemy(e) {
+            if (e.dead) return;
+            e.dead = true;
+            gold += e.reward;
+            score += e.reward;
+            sfx.kill();
+            addParticles(e.x, e.y + BAR_H, e.color, 8);
+            addFloat(e.x, e.y + BAR_H, '+' + e.reward, '#facc15');
+        }
+
+        // ── Projectile movement ───────────────────────────────
+        function moveProjectile(p, dt) {
+            if (p.visual) {
+                p.visualLife -= dt;
+                if (p.visualLife <= 0) p.done = true;
+                return;
+            }
+            if (!p.target || p.target.dead) { p.done = true; return; }
+            p.tx = p.target.x; p.ty = p.target.y;
+            const dx = p.tx - p.x, dy = p.ty - p.y;
+            const dist = Math.hypot(dx, dy);
+            const move = p.speed * dt;
+            if (dist <= move) {
+                // Hit
+                if (p.type === 'splash') {
+                    for (const e of enemies) {
+                        if (e.dead) continue;
+                        const d = Math.hypot(e.x - p.tx, e.y - p.ty);
+                        if (d <= p.splashRadius) {
+                            e.hp -= p.damage * (1 - d / p.splashRadius * 0.5);
+                            if (e.hp <= 0) killEnemy(e);
+                        }
+                    }
+                    addParticles(p.tx, p.ty + BAR_H, '#fdba74', 12);
+                } else {
+                    p.target.hp -= p.damage;
+                    if (p.type === 'slow') {
+                        p.target.slowTimer = p.slowDuration;
+                        p.target.slowFactor = p.slowFactor;
+                    }
+                    if (p.target.hp <= 0) killEnemy(p.target);
+                    else addParticles(p.tx, p.ty + BAR_H, p.color, 3);
+                }
+                p.done = true;
+            } else {
+                p.x += (dx / dist) * move;
+                p.y += (dy / dist) * move;
+            }
+        }
+
+        // ── Game Over ─────────────────────────────────────────
+        function endGame(won) {
+            gamePhase = won ? 'won' : 'over';
+            const rank = saveScore('tower-defense', wave, 'normal');
+
+            const ol = document.getElementById('overlay');
+            ol.innerHTML = won
+                ? `<div class="ov-title" style="color:#22c55e;text-shadow:0 0 30px rgba(34,197,94,0.7)">YOU WIN!</div>
+                   <div class="ov-score">WAVE ${wave} CLEARED</div>
+                   <div class="ov-score" style="color:#facc15">GOLD EARNED: ${score}</div>
+                   <button class="ov-btn" id="restartBtn" style="background:#22c55e">PLAY AGAIN</button>`
+                : `<div class="ov-title" style="colo

