+                    ctx.strokeStyle = t.color; ctx.lineWidth = 3; ctx.stroke();
+                }
+                ctx.restore();
+                ctx.shadowBlur = 0;
+
+                // Upgrade pips
+                for (let i = 0; i < t.upgradeLevel; i++) {
+                    ctx.fillStyle = '#facc15';
