+                }
+            }
+        }
+
+        // ── Draw enemies ──────────────────────────────────────
+        function drawEnemies() {
+            for (const e of enemies) {
+                if (e.dead) continue;
+                const ex = e.x, ey = e.y + BAR_H;
+
+                // Slow tint
+                if (e.slowTimer > 0) {
+                    ctx.beginPath();
+                    ctx.arc(ex, ey, e.size + 4, 0, Math.PI * 2);
+                    ctx.fillStyle = 'rgba(56,189,248,0.2)';
+                    ctx.fill();
+                }
+
+                // Enemy body
+                ctx.beginPath();
+                ctx.arc(ex, ey, e.size, 0, Math.PI * 2);
+                ctx.fillStyle = e.color;
+                ctx.fill();
+                ctx.strokeStyle = '#fff2';
+                ctx.lineWidth = 1;
+                ctx.stroke();
+
+                // Direction indicator
+                if (e.wpIdx < WAYPOINTS.length) {
+                    const [tx, ty] = WAYPOINTS[e.wpIdx];
+                    const ang = Math.atan2(ty - e.y, tx - e.x);
+                    ctx.beginPath();
+                    ctx.moveTo(ex + Math.cos(ang) * e.size, ey + Math.sin(ang) * e.size);
+                    ctx.lineTo(
+                        ex + Math.cos(ang) * (e.size + 5),
+                        ey + Math.sin(ang) * (e.size + 5)
+                    );
+                    ctx.strokeStyle = '#fff6';
+                    ctx.lineWidth = 2;
+                    ctx.stroke();
+                }
+
+                // HP bar
+                const barW = e.size * 2.5, barH = 3;
+                const bx = ex - barW / 2, by = ey - e.size - 6;
+                ctx.fillStyle = '#1f2937';
+                ctx.fillRect(bx, by, barW, barH);
+                const pct = Math.max(0, e.hp / e.maxHp);
+                ctx.fillStyle = pct > 0.5 ? '#22c55e' : pct > 0.25 ? '#facc15' : '#ef4444';
+                ctx.fillRect(bx, by, barW * pct, barH);
+            }
+        }
+
+        // ── Draw projectiles ──────────────────────────────────
+        function drawProjectiles() {
+            for (const p of projectiles) {
+                if (p.visual) {
+                    // Lightning bolt visual
+                    ctx.beginPath();
+                    ctx.moveTo(p.x, p.y + BAR_H);
+                    ctx.lineTo(p.tx, p.ty + BAR_H);
+                    ctx.strokeStyle = p.color;
+                    ctx.lineWidth = 2;
+                    ctx.shadowColor = p.color;
+                    ctx.shadowBlur = 6;
+                    ctx.stroke();
+                    ctx.shadowBlur = 0;
+                    continue;
+                }
+                const py = p.y + BAR_H;
+                const pty = p.ty + BAR_H;
+
+                if (p.type === 'splash') {
+                    ctx.beginPath();
+                    ctx.arc(p.x, py, 5, 0, Math.PI * 2);
+                    ctx.fillStyle = p.color;
+                    ctx.shadowColor = p.color;
+                    ctx.shadowBlur = 8;
+                    ctx.fill();
+                    ctx.shadowBlur = 0;
+                } else {
+                    ctx.beginPath();
+                    ctx.arc(p.x, py, 3, 0, Math.PI * 2);
+                    ctx.fillStyle = p.color;
+                    ctx.shadowColor = p.color;
+                    ctx.shadowBlur = 5;
+                    ctx.fill();
+                    ctx.shadowBlur = 0;
+                }
+            }
+        }
+
+        // ── Draw particles ────────────────────────────────────
+        function drawParticles() {
