+            ctx.lineWidth = 1;
+            ctx.beginPath(); ctx.moveTo(0, BAR_H); ctx.lineTo(CW, BAR_H); ctx.stroke();
+
+            const items = [
+                { label: '♥', value: lives,       color: '#ef4444', x: 12  },
+                { label: '$', value: gold,         color: '#facc15', x: 130 },
+                { label: '≋', value: `${wave}/${TOTAL_WAVES}`, color: '#a855f7', x: 280 },
+                { label: '★', value: score,        color: '#38bdf8', x: 430 },
+            ];
+
+            for (const it of items) {
+                ctx.font = '8px "Press Start 2P"';
+                ctx.textAlign = 'left';
+                ctx.textBaseline = 'middle';
+                ctx.fillStyle = it.color;
+                ctx.shadowColor = it.color;
+                ctx.shadowBlur = 6;
+                ctx.fillText(it.label, it.x, BAR_H / 2);
+                ctx.shadowBlur = 0;
