+                ctx.fillStyle = '#ef4444';
+                ctx.shadowColor = '#ef4444';
+                ctx.shadowBlur = 4;
+                ctx.fillText(`WAVE ${wave}  ×${rem}`, CW - SIDE_W - 10, BAR_H / 2);
+                ctx.shadowBlur = 0;
+            }
+        }
