+                ctx.textBaseline = 'middle';
+                ctx.fillStyle = '#1e293b';
+                ctx.fillText('CLICK TOWER', sx + SIDE_W / 2, upgY0 + 10);
+                ctx.fillText('TO UPGRADE', sx + SIDE_W / 2, upgY0 + 24);
+            }
+        }
+
+        // ── Main draw ─────────────────────────────────────────
+        function draw() {
+            ctx.clearRect(0, 0, CW, CH);
+            drawGrid();
+            drawPath();
+            drawTowers();
+            drawEnemies();
+            drawProjectiles();
+            drawParticles();
+            drawFloats();
+            drawTopBar();
+            drawSidebar();
+        }
+
+        // ── Game loop ─────────────────────────────────────────
+        function loop(ts) {
