+        }
+
+        // ── Start ─────────────────────────────────────────────
+        document.getElementById('startBtn').addEventListener('click', () => {
+            document.getElementById('overlay').classList.remove('show');
+            resetGame();
+            requestAnimationFrame(ts => { lastTime = ts; loop(ts); });
+        });
+
+        // Initial draw (static)
+        resetGame();
+        draw();
+    </script>
+</body>
