function startWave() {
    if (waveActive || wave >= TOTAL_WAVES) return;
    wave++;
    waveEnemies = makeWave(wave);
    waveSpawnIdx = 0;
    waveSpawnTimer = 0;
    waveActive = true;
    waveComplete = false;
    sfx.wave();
    // Bonus gold for early start
    if (waveCountdown > 0) {
        const bonus = Math.floor(waveCountdown) * 2;
        gold += bonus;
        addFloat(GRID_W / 2, BAR_H / 2, `+${bonus} EARLY!`, '#facc15');
    }
}

// ── Projectile factory ────────────────────────────────
function createProjectile(tower, target) {
    return {
        x: tower.x, y: tower.y,
        tx: target.x, ty: target.y,
        target,
        damage: tower.damage,
        speed: tower.projSpeed,
        color: tower.projColor,
        type: tower.type,
        splashRadius: tower.splashRadius,
        slowFactor: tower.slowFactor,
        slowDuration: tower.slowDuration,
        chainCount: tower.chainCount,
        chainRange: tower.chainRange,
        done: false,
    };
}

// ── Float text factory ────────────────────────────────
function addFloat(x, y, text, color) {
    floats.push({ x, y, text, color, life: 1.0 });
}

