function endGame(won) {
    gamePhase = won ? 'won' : 'over';
    const rank = saveScore('tower-defense', wave, 'normal');

    const ol = document.getElementById('overlay');
    ol.innerHTML = won
        ? `<div class="ov-title" style="color:#22c55e;text-shadow:0 0 30px rgba(34,197,94,0.7)">YOU WIN!</div>
